parameters.jsCode:
const raw = $('Project Manager ').item.json.output;

function parseProjectManagerOutput(value) {
  if (Array.isArray(value)) return value;
  if (value && Array.isArray(value.schedule)) return value.schedule;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    try {
      const parsed = JSON.parse(trimmed);
      if (Array.isArray(parsed)) return parsed;
      if (parsed && Array.isArray(parsed.schedule)) return parsed.schedule;
    } catch {}
    const start = trimmed.indexOf('[');
    const end = trimmed.lastIndexOf(']');
    if (start !== -1 && end !== -1 && end > start) {
      const fragment = trimmed.slice(start, end + 1);
      return JSON.parse(fragment);
    }
  }
  throw new Error('Project Manager output is not valid JSON array data.');
}

function normalizeWbs(wbs) {
  return String(wbs || '').trim();
}

function normalizeActivityName(name) {
  return String(name || '').trim().replace(/\s{2,}/g, ' ');
}

function normalizePredecessor(value) {
  return String(value || '').trim();
}

function normalizeDuration(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return 1;
  return n === 0 ? 0 : Math.max(1, Math.round(n));
}

const rows = parseProjectManagerOutput(raw)
  .map((row) => ({
    "WBS": normalizeWbs(row["WBS"] ?? row.wbs),
    "Activity Name": normalizeActivityName(row["Activity Name"] ?? row.activity_name),
    "Duration (Days)": normalizeDuration(row["Duration (Days)"] ?? row.duration_days),
    "Predecessor(s)": normalizePredecessor(row["Predecessor(s)"] ?? row.predecessors),
  }))
  .filter((row) => row["WBS"] && row["Activity Name"]);

const seen = new Set();
const unique = rows.filter((row) => {
  const key = `${row["WBS"]}||${row["Activity Name"]}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return unique.map((row) => ({ json: row }));
